const item = $input.first().json;
const subject = item.subject || '';
const text = item.textPlain || item.textHtml || item.text || '';
const from = item.from?.value?.[0]?.address || item.from || '';
const fromName = item.from?.value?.[0]?.name || '';
const raw = `${subject}\n${text}`.toLowerCase();
const intakeLink = 'https://review-metrics-roadmap.replit.app/client-intake/';

const hotWords = ['מחיר', 'הצעת מחיר', 'דחוף', 'שיחה', 'לקנות', 'רוצה להתחיל', 'תקציב', 'פגישה', 'quote', 'pricing', 'urgent', 'call', 'demo'];
const supportWords = ['תמיכה', 'בעיה', 'תקלה', 'לא עובד', 'חשבונית', 'support', 'bug', 'issue', 'invoice'];
const spamWords = ['seo', 'backlinks', 'crypto', 'casino', 'loan', 'viagra'];

let leadStatus = 'warm';
if (spamWords.some((word) => raw.includes(word))) leadStatus = 'spam';
else if (supportWords.some((word) => raw.includes(word))) leadStatus = 'support';
else if (hotWords.some((word) => raw.includes(word))) leadStatus = 'hot';
else if (raw.length < 40) leadStatus = 'cold';

const replies = {
  hot: `שלום${fromName ? ' ' + fromName : ''},\n\nתודה שפנית אלינו. קיבלנו את הפנייה ונראה שיש כאן צורך שנוכל לעזור איתו במהירות.\n\nכדי שנוכל לאפיין את הצורך בצורה מדויקת ולחזור אליך עם כיוון מתאים, אפשר להתחיל כאן:\n${intakeLink}\n\nאפשר גם להשיב למייל הזה עם זמן נוח לשיחה קצרה.\n\nבברכה,\nAgentHub Guru`,
  warm: `שלום${fromName ? ' ' + fromName : ''},\n\nתודה על הפנייה. קיבלנו את הפרטים ונחזור אליך בהקדם.\n\nכדי שנוכל לכוון אותך טוב יותר, אפשר להשלים איפיון קצר כאן:\n${intakeLink}\n\nבברכה,\nAgentHub Guru`,
  cold: `שלום${fromName ? ' ' + fromName : ''},\n\nתודה על הפנייה. קיבלנו את המייל שלך.\n\nכדי שנוכל להבין איך לעזור, אפשר להתחיל מאיפיון קצר כאן:\n${intakeLink}\n\nבברכה,\nAgentHub Guru`,
  support: `שלום${fromName ? ' ' + fromName : ''},\n\nתודה שיצרת קשר. קיבלנו את הפנייה והיא הועברה לטיפול.\n\nנחזור אליך בהקדם עם עדכון.\n\nבברכה,\nAgentHub Guru`,
  spam: ''
};

return [{
  json: {
    from,
    fromName,
    subject,
    body: text,
    leadStatus,
    intakeLink,
    replySubject: subject ? `Re: ${subject}` : 'תודה על פנייתך',
    replyBody: replies[leadStatus],
    shouldReply: leadStatus !== 'spam'
  }
}];
